  ('real-estate-moex-00621', 'real-estate', 'real-estate-moex-109-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲乙夫妻婚後育有一子丙，三人與甲寡居之母親丁同住。甲乙兩人因感情不睦，故協議離婚，惟 某日前往辦理離婚登記途中，甲不幸發生事故身亡。甲生前曾預立有效遺囑一份，記載將來所有 遺產均由獨子丙繼承。甲身後遺有現金600萬元。若繼承人主張特留分扣減權時，甲之遺產應如 何分配？', '["乙繼承300萬元，丙繼承300萬元", "乙繼承150萬元，丙繼承450萬元", "乙繼承200萬元，丁繼承200萬元，丙繼承200萬元", "乙繼承100萬元，丁繼承100萬元，丙繼承400萬元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:37+00:00", "source_pdf_sha1": "190d1fea1d2c", "answer_pdf_sha1": "3215d99df64b", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "601", "s": "1201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
